export const normalizeUiLookupKey = (value: string): string =>
  value.replace(/\s+/g, ' ').trim();

export const buildUiLocaleBundle = (language: LanguageCode): UiLocaleBundle => {
  const lookup = new Map<string, string>();
  const targetIndex = LANGUAGE_INDEX[language];

  EXACT_UI_ROWS.forEach((row) => {
    const target = row[targetIndex] || row[0] || row[1];
    const aliases = [row[0], row[1]];

    aliases.forEach((source) => {
      const key = normalizeUiLookupKey(source);
      if (key && !lookup.has(key)) {
        lookup.set(key, target);
      }
    });
  });

  EXTENDED_UI_ROWS.forEach((row) => {
    const target = row[targetIndex] || row[0] || row[1];
    const aliases = [row[0], row[1]];

    aliases.forEach((source) => {
      const key = normalizeUiLookupKey(source);
      if (key && !lookup.has(key)) {
        lookup.set(key, target);
      }
    });
  });

  GENERATED_SITE_PHRASE_ROWS.forEach(([en, ar]) => {
    const target = language === 'ar' ? ar : en;
    [en, ar].forEach((source) => {
      const key = normalizeUiLookupKey(source);
      if (key && !lookup.has(key)) {
        lookup.set(key, target);
      }
    });
  });

  MANUAL_SITE_PHRASE_ROWS.forEach(([en, ar]) => {
    const target = language === 'ar' ? ar : en;
    [en, ar].forEach((source) => {
      const key = normalizeUiLookupKey(source);
      if (key && !lookup.has(key)) {
        lookup.set(key, target);
      }
    });
  });

  return { lookup };
};
